effect.shader:
void main() {
    //float hue = 0.0;
    highp mat3 rgb2yuv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );
    highp mat3 yuv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );
    //float rad = hue * 0.0174533;
    //highp mat3 huemat = mat3(
    //    1.0,  0.0,       0.0,
    //    0.0,  cos(rad),  sin(rad),
    //    0.0,  -sin(rad), cos(rad)
    //);
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    highp vec3 rgb = texColor.rgb;
    lowp float a = texColor.a;
    highp vec3 yuv = rgb * rgb2yuv;

    //-- Vibrance 1 --
    float origSat = min(1.0,length(yuv.yz)*2.5); //
    vec2 satUV = yuv.yz * vib;
    yuv.yz = mix(satUV,yuv.yz,origSat);
    //--------------

    //-- Vibrance 2 --
    //float origSat = min(1.0,length(yuv.yz)*2.5); //
    //vec2 satUV = yuv.yz * pow(origSat+1.0,vib);
    //yuv.yz = mix(satUV,yuv.yz,origSat);
    //--------------

    yuv.yz = yuv.yz * (saturation+1.0);
    //yuv = yuv * huemat;
    //yuv.x = (yuv.x-0.5*a) * (contrast+1.0) + 0.5*a + brightness*a;
    rgb = yuv * yuv2rgb;
    //rgb = (rgb - 0.5) * (contrast+1.0) + 0.5 + brightness;
    gl_FragColor = vec4(rgb,a);
}
